import{_ as n,c as t,a2 as d,G as o,B as e,o as p}from"./chunks/framework.DUe8d0tq.js";const m=JSON.parse('{"title":"发布部署","description":"","frontmatter":{},"headers":[],"relativePath":"deploy/wx-release.md","filePath":"deploy/wx-release.md"}'),c={name:"deploy/wx-release.md"};function r(s,a,g,x,_,h){const l=e("NolebaseGitContributors"),i=e("NolebaseGitChangelog");return p(),t("div",null,[a[0]||(a[0]=d('<h1 id="发布部署" tabindex="-1">发布部署 <a class="header-anchor" href="#发布部署" aria-label="Permalink to &quot;发布部署&quot;">​</a></h1><p>该内容会引导您发布和部署微信小程序。</p><h2 id="_9-发布小程序" tabindex="-1">9. 发布小程序 <a class="header-anchor" href="#_9-发布小程序" aria-label="Permalink to &quot;9. 发布小程序&quot;">​</a></h2><h3 id="_9-1-配置服务器域名" tabindex="-1">9.1 配置服务器域名 <a class="header-anchor" href="#_9-1-配置服务器域名" aria-label="Permalink to &quot;9.1 配置服务器域名&quot;">​</a></h3><p>在 微信小程序后台，找到菜单 <code>管理-开发管理-服务器域名</code></p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_22-59-38.png" alt="PixPin_2025-08-15_22-59-38.png" data-fancybox="gallery" loading="lazy"></p><p>点击 <code>修改</code> 按钮后弹出，配置修改的弹窗，分别在 <code>request合法域名</code> <code>uploadFile合法域名</code> <code>downloadFile合法域名</code> 中填写你的博客域名，点击 <code>保存并提交</code> 即可。</p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_23-03-18.png" alt="PixPin_2025-08-15_23-03-18.png" data-fancybox="gallery" loading="lazy"></p><h3 id="_9-2-预览" tabindex="-1">9.2 预览 <a class="header-anchor" href="#_9-2-预览" aria-label="Permalink to &quot;9.2 预览&quot;">​</a></h3><p>在 <code>HBuilder X</code> 开发工具中，点击菜单栏 <code>构建 -&gt; 小程序-微信</code></p><p><img src="https://blog.xiaoxiaomo.cn/upload/image-fWTY.png" alt="image-fWTY.png" data-fancybox="gallery" loading="lazy"></p><p>接着，在弹窗中点击 <code>构建</code> 按钮，等待编译构建</p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_22-04-17.png" alt="PixPin_2025-08-15_22-04-17.png" data-fancybox="gallery" loading="lazy"></p><p>构建完成后会自动打开微信开发工具</p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_22-28-46.png" alt="PixPin_2025-08-15_22-28-46.png" data-fancybox="gallery" loading="lazy"></p><p>点击微信开发工具上方的 <code>预览</code> 按钮，等待片刻就可以使用微信扫码预览</p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_22-30-35.png" alt="PixPin_2025-08-15_22-30-35.png" data-fancybox="gallery" loading="lazy"></p><h3 id="_9-3-部署" tabindex="-1">9.3 部署 <a class="header-anchor" href="#_9-3-部署" aria-label="Permalink to &quot;9.3 部署&quot;">​</a></h3><p>在预览没有问题的时候，我们依然在 <code>微信开发工具</code> 中，点击右上角的 <code>上传</code> 按钮，在弹出的弹窗中，点击 <code>确定</code></p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_22-33-46.png" alt="PixPin_2025-08-15_22-33-46.png" data-fancybox="gallery" loading="lazy"></p><p>接着继续 在弹出弹窗中 继续填写 <code>版本号</code> 和 <code>项目备注</code>，最后点击 <code>提交</code> 按钮，等待片刻上传成功，会显示一个提示。</p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_22-36-10.png" alt="PixPin_2025-08-15_22-36-10.png" data-fancybox="gallery" loading="lazy"></p><h3 id="_9-4-体验" tabindex="-1">9.4 体验 <a class="header-anchor" href="#_9-4-体验" aria-label="Permalink to &quot;9.4 体验&quot;">​</a></h3><p>这里的体验，可以发给其他人进行体验，但是目前还无法搜索到，只能通过二维码发送给其他人体验。</p><p>在上一步 <code>部署</code> 完成后，我们打开 微信管理后台，找到菜单 <code>管理-版本管理-开发版本</code>，找到蓝色的 <code>体验版</code> 按钮，点击后可以弹出体验版的二维码，手机扫码后，要是没有问题，就可以往下继续，提交审核。</p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_22-39-46.png" alt="PixPin_2025-08-15_22-39-46.png" data-fancybox="gallery" loading="lazy"></p><h3 id="_9-5-审核" tabindex="-1">9.5 审核 <a class="header-anchor" href="#_9-5-审核" aria-label="Permalink to &quot;9.5 审核&quot;">​</a></h3><p>在微信小程序后台提交审核，找到菜单 <code>管理-版本管理-开发版本</code>，点击右侧的 <code>提交审核</code> 按钮</p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_21-51-03.png" alt="PixPin_2025-08-15_21-51-03.png" data-fancybox="gallery" loading="lazy"></p><p>进入审核信息填写界面，填写审核信息，然后点击提交审核即可。</p><p>推荐填写：<em>个人日记小程序，用于记录个人工作和生活</em></p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_21-53-04.png" alt="PixPin_2025-08-15_21-53-04.png" data-fancybox="gallery" loading="lazy"></p><p><img src="https://blog.xiaoxiaomo.cn/upload/PixPin_2025-08-15_21-55-34.png" alt="PixPin_2025-08-15_21-55-34.png" data-fancybox="gallery" loading="lazy"></p><details class="details custom-block"><summary>提交审核时候的建议</summary><p>为了能够更容易通过审核，作者建议：</p><ul><li><ol><li>在填写审核信息的时候，若您的小程序资质是 <code>个人资质</code> 尽可能将您的描述信息写为个人类型的内容，如参考作者的小程序描述：<strong>这里是我的个人日记小程序，用于记录个人的工作和生活。</strong></li></ol></li><li><ol start="2"><li>上传截图的时候，请不要截图有关于社交部分的内容，比如：评论区</li></ol></li><li><ol start="3"><li>文章内容可以先将带有分享性质的文章先进行下架，保留一些个人的日志文章等等</li></ol></li></ul></details><h3 id="_9-6-上线" tabindex="-1">9.6 上线 <a class="header-anchor" href="#_9-6-上线" aria-label="Permalink to &quot;9.6 上线&quot;">​</a></h3><p>等待审核通过，通过后还是在 <code>管理-版本管理-审核版本</code> 中可以看到，然后点击发布上线即可。</p>',36)),o(l),o(i)])}const b=n(c,[["render",r]]);export{m as __pageData,b as default};
